//! Sample **CSV** file generation from any [`CellSource`] (functional_spec §5.3:
//! inputs are generated by committed code, never hand-made binaries).
//!
//! CSV is dependency-free, so it lives here. `.xlsx` sample generation is
//! **deliberately deferred**: the xlsx-writer choice (`umya-spreadsheet` /
//! `rust_xlsxwriter` / engine-native) is gated by Sub-project A/B (architecture
//! §6, §9). Once chosen, Sub-project B owns xlsx generation in its own crate — this
//! shared, frozen crate must not couple to a writer that may not be selected.

use std::io::{self, Write};

use crate::cell::{CellSource, CellValue};

/// Writes `rows × cols` cells from `source` as RFC-4180-ish CSV to `writer`.
///
/// - `Number` cells are written with `{}` float formatting.
/// - `Text` cells are quoted only when they contain a comma, quote, CR, or LF;
///   embedded quotes are doubled.
/// - `Empty` cells are written as an empty field.
///
/// Line endings are `\n`. Output is fully determined by `source`, so re-running is
/// reproducible.
pub fn write_csv<W: Write>(
    writer: &mut W,
    source: &dyn CellSource,
    rows: u32,
    cols: u32,
) -> io::Result<()> {
    for r in 0..rows {
        for c in 0..cols {
            if c > 0 {
                writer.write_all(b",")?;
            }
            let field = format_field(&source.cell(r, c).value);
            writer.write_all(field.as_bytes())?;
        }
        writer.write_all(b"\n")?;
    }
    Ok(())
}

/// Convenience wrapper over [`write_csv`] that returns a `String`.
pub fn csv_string(source: &dyn CellSource, rows: u32, cols: u32) -> String {
    let mut buf = Vec::new();
    // Writing to a `Vec<u8>` is infallible.
    write_csv(&mut buf, source, rows, cols).expect("writing to Vec cannot fail");
    String::from_utf8(buf).expect("cell text is valid UTF-8")
}

/// Formats a single cell value as a CSV field, quoting/escaping text when needed.
fn format_field(value: &CellValue) -> String {
    match value {
        CellValue::Empty => String::new(),
        CellValue::Number(n) => n.to_string(),
        CellValue::Text(t) => {
            if t.contains([',', '"', '\n', '\r']) {
                let escaped = t.replace('"', "\"\"");
                format!("\"{escaped}\"")
            } else {
                t.clone()
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::cell::{CellData, CellFormat};
    use crate::synthetic::SyntheticSheet;

    /// A tiny hand-built source for exercising escaping precisely.
    struct FixedSource;
    impl CellSource for FixedSource {
        fn cell(&self, row: u32, col: u32) -> CellData {
            let value = match (row, col) {
                (0, 0) => CellValue::Text("plain".into()),
                (0, 1) => CellValue::Text("has,comma".into()),
                (0, 2) => CellValue::Text("has\"quote".into()),
                (1, 0) => CellValue::Number(3.5),
                (1, 1) => CellValue::Empty,
                _ => CellValue::Text("x".into()),
            };
            CellData {
                value,
                format: CellFormat::default(),
            }
        }
    }

    #[test]
    fn csv_escaping_rules() {
        let csv = csv_string(&FixedSource, 2, 3);
        let lines: Vec<&str> = csv.lines().collect();
        assert_eq!(lines.len(), 2);
        assert_eq!(lines[0], r#"plain,"has,comma","has""quote""#);
        assert_eq!(lines[1], "3.5,,x");
    }

    #[test]
    fn csv_roundtrip_shape_and_determinism() {
        let sheet = SyntheticSheet::new(21, 100, 6);
        let a = csv_string(&sheet, 8, 6);
        let b = csv_string(&sheet, 8, 6);
        // Deterministic.
        assert_eq!(a, b);
        // Right number of rows.
        let lines: Vec<&str> = a.lines().collect();
        assert_eq!(lines.len(), 8);
        // Right number of columns on a line whose fields contain no embedded commas
        // is exactly cols-1 separators; verify against a line we can count safely by
        // re-generating with all-numeric-free content is hard, so assert each line
        // has at least cols-1 top-level commas by splitting on a simple heuristic:
        // count fields via a minimal parser.
        for line in &lines {
            assert_eq!(count_fields(line), 6, "line has wrong field count: {line}");
        }
    }

    #[test]
    fn write_csv_matches_csv_string() {
        let sheet = SyntheticSheet::new(1, 10, 4);
        let via_string = csv_string(&sheet, 5, 4);
        let mut buf = Vec::new();
        write_csv(&mut buf, &sheet, 5, 4).unwrap();
        assert_eq!(String::from_utf8(buf).unwrap(), via_string);
    }

    /// Minimal RFC-4180 field counter (handles quoted fields with embedded commas)
    /// used only to validate generated CSV column counts in tests.
    fn count_fields(line: &str) -> usize {
        let mut fields = 1;
        let mut in_quotes = false;
        let mut chars = line.chars().peekable();
        while let Some(ch) = chars.next() {
            match ch {
                '"' => {
                    if in_quotes && chars.peek() == Some(&'"') {
                        chars.next(); // escaped quote
                    } else {
                        in_quotes = !in_quotes;
                    }
                }
                ',' if !in_quotes => fields += 1,
                _ => {}
            }
        }
        fields
    }
}
